+            ..ScriptBotsConfig::default()
+        };
+
+        let mut world = WorldState::new(config).expect("world");
+        world.spawn_agent(sample_agent(0));
+
+        let mut ages = Vec::new();
+        for _ in 0..10 {
+            world.step();
+            ages.push(world.agents().columns().ages()[0]);
+        }
+
+        assert!(ages.iter().take(4).all(|age| *age == 0));
+        assert_eq!(ages[4], 1);
